+    eprintln!("BEFORE FrankenConnection ({} entries):", schema_before.len());
+    for s in &schema_before {
+        eprintln!("  {s}");
+    }
+    drop(conn);
+
+    // 3. Open with FrankenConnection and do a write
+    let fconn = DbConn::open_file(&path_str).expect("open franken");
+    fconn
