+/// Does corruption happen with AUTOINCREMENT specifically?
+#[test]
+fn frankenconnection_autoincrement_write() {
+    use mcp_agent_mail_db::DbConn;
+
+    let dir = tempfile::tempdir().expect("tempdir");
